SELECT MAX(loss) AS max_loss
FROM experiment_results
WHERE experiment_id = 1;

SELECT experiment_name
FROM experiments
ORDER BY experiment_name;

SELECT AVG(loss) AS average_loss, MAX(loss) AS max_loss
FROM experiment_results
WHERE experiment_id = 1;

SELECT DISTINCT experiment_name 
FROM experiments 
WHERE status IN ('active', 'completed');

SELECT experiment_id
FROM experiments
WHERE status = 'completed' AND environment = 'production';
